@import "tailwindcss";

:root {
  --background: #ffffff;
  --foreground: #171717;
  --accent: #2563eb;
  --accent-hover: #1d4ed8;
  --muted: #6b7280;
  --border: #e5e7eb;
  --card-bg: #f9fafb;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
}

@media (prefers-color-scheme: dark) {
  :root {
    --background: #0a0a0a;
    --foreground: #ededed;
    --accent: #3b82f6;
    --accent-hover: #60a5fa;
    --muted: #9ca3af;
    --border: #27272a;
    --card-bg: #18181b;
  }
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-sans, Arial, Helvetica, sans-serif);
}

'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';

const links = [
  { href: '/', label: 'Home' },
  { href: '/about', label: 'About' },
  { href: '/services', label: 'Services' },
  { href: '/contact', label: 'Contact' },
];

export default function Navbar() {
  const pathname = usePathname();

  return (
    <nav className="border-b border-[var(--border)] bg-[var(--background)]/80 backdrop-blur-sm sticky top-0 z-50">
      <div className="max-w-5xl mx-auto px-6 h-16 flex items-center justify-between">
        <Link href="/" className="text-xl font-bold tracking-tight">
          paysdoc<span className="text-[var(--accent)]">.nl</span>
        </Link>
        <div className="flex gap-6">
          {links.map(({ href, label }) => (
            <Link
              key={href}
              href={href}
              className={`text-sm transition-colors ${
                pathname === href
                  ? 'text-[var(--accent)] font-medium'
                  : 'text-[var(--muted)] hover:text-[var(--foreground)]'
              }`}
            >
              {label}
            </Link>
          ))}
        </div>
      </div>
    </nav>
  );
}

import Link from 'next/link';

export default function Footer() {
  return (
    <footer className="border-t border-[var(--border)] mt-auto">
      <div className="max-w-5xl mx-auto px-6 py-8 flex flex-col sm:flex-row items-center justify-between gap-4 text-sm text-[var(--muted)]">
        <p>&copy; {new Date().getFullYear()} paysdoc.nl. All rights reserved.</p>
        <div className="flex gap-6">
          <Link href="https://github.com/paysdoc" className="hover:text-[var(--foreground)] transition-colors">
            GitHub
          </Link>
          <Link href="/contact" className="hover:text-[var(--foreground)] transition-colors">
            Contact
          </Link>
        </div>
      </div>
    </footer>
  );
}

interface SkillCardProps {
  title: string;
  description: string;
  icon: string;
}

export default function SkillCard({ title, description, icon }: SkillCardProps) {
  return (
    <div className="p-6 rounded-xl border border-[var(--border)] bg-[var(--card-bg)] hover:border-[var(--accent)] transition-colors">
      <div className="text-3xl mb-4">{icon}</div>
      <h3 className="text-lg font-semibold mb-2">{title}</h3>
      <p className="text-sm text-[var(--muted)]">{description}</p>
    </div>
  );
}

interface ServiceCardProps {
  title: string;
  description: string;
  features: string[];
}

export default function ServiceCard({ title, description, features }: ServiceCardProps) {
  return (
    <div className="p-8 rounded-xl border border-[var(--border)] bg-[var(--card-bg)]">
      <h3 className="text-xl font-semibold mb-3">{title}</h3>
      <p className="text-[var(--muted)] mb-6">{description}</p>
      <ul className="space-y-2">
        {features.map((feature) => (
          <li key={feature} className="flex items-start gap-2 text-sm">
            <span className="text-[var(--accent)] mt-0.5">&#10003;</span>
            {feature}
          </li>
        ))}
      </ul>
    </div>
  );
}

'use client';

export default function CalEmbed({ calLink }: { calLink: string }) {
  return (
    <div className="w-full rounded-xl overflow-hidden border border-[var(--border)]">
      <iframe
        src={`https://cal.com/${calLink}?embed=true&theme=auto`}
        className="w-full border-0"
        style={{ height: '700px' }}
        title="Book a discovery call"
      />
    </div>
  );
}

